import { useState } from "react";
import Button from "../components/Button";

const demoOrderHistory = [
  {
    id: "ORD-13284",
    date: "Feb 20, 2026",
    status: "Delivered",
    total: "$149.99",
  },
  {
    id: "ORD-12910",
    date: "Jan 11, 2026",
    status: "Shipped",
    total: "$89.99",
  },
];

function LoginPage() {
  const [formData, setFormData] = useState({
    email: "",
    password: "",
    rememberMe: false,
  });
  const [activeUser, setActiveUser] = useState(() => {
    const storedUser = localStorage.getItem("ecommerce_demo_user");
    return storedUser ? JSON.parse(storedUser) : null;
  });

  const handleLogin = (event) => {
    event.preventDefault();
    const user = {
      name: "Oliver Stone",
      email: formData.email || "user@novacart.com",
    };
    setActiveUser(user);
    if (formData.rememberMe) {
      localStorage.setItem("ecommerce_demo_user", JSON.stringify(user));
    } else {
      localStorage.removeItem("ecommerce_demo_user");
    }
  };

  const handleLogout = () => {
    setActiveUser(null);
    localStorage.removeItem("ecommerce_demo_user");
  };

  return (
    <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">
      <h1 className="mb-6 text-2xl font-bold text-slate-900">Login & Profile</h1>

      <div className="grid gap-6 lg:grid-cols-2">
        <section className="rounded-xl border border-slate-100 bg-white p-6 shadow-md">
          <h2 className="text-xl font-bold text-slate-900">Login</h2>
          <form className="mt-5 space-y-4" onSubmit={handleLogin}>
            <InputField
              label="Email"
              onChange={(event) =>
                setFormData((current) => ({ ...current, email: event.target.value }))
              }
              type="email"
              value={formData.email}
            />
            <InputField
              label="Password"
              onChange={(event) =>
                setFormData((current) => ({
                  ...current,
                  password: event.target.value,
                }))
              }
              type="password"
              value={formData.password}
            />

            <label className="flex items-center gap-2 text-sm text-slate-600">
              <input
                checked={formData.rememberMe}
                className="h-4 w-4 rounded border-slate-300 text-primary-600 focus:ring-primary-500"
                onChange={(event) =>
                  setFormData((current) => ({
                    ...current,
                    rememberMe: event.target.checked,
                  }))
                }
                type="checkbox"
              />
              Remember me
            </label>

            <Button className="w-full" type="submit" variant="primary">
              Login
            </Button>
          </form>

          <div className="mt-6">
            <p className="mb-3 text-center text-xs font-semibold uppercase tracking-wide text-slate-400">
              Or continue with
            </p>
            <div className="grid grid-cols-2 gap-3">
              <Button className="w-full" variant="ghost">
                Google
              </Button>
              <Button className="w-full" variant="ghost">
                Facebook
              </Button>
            </div>
          </div>
        </section>

        <section className="rounded-xl border border-slate-100 bg-white p-6 shadow-md">
          <h2 className="text-xl font-bold text-slate-900">My Account</h2>
          {activeUser ? (
            <div className="mt-5 space-y-5">
              <div className="rounded-xl bg-primary-50 p-4">
                <p className="text-sm font-semibold text-primary-700">{activeUser.name}</p>
                <p className="mt-1 text-sm text-slate-600">{activeUser.email}</p>
              </div>

              <div>
                <h3 className="text-sm font-semibold uppercase tracking-wide text-slate-500">
                  Order History
                </h3>
                <div className="mt-3 space-y-3">
                  {demoOrderHistory.map((order) => (
                    <div
                      className="rounded-xl border border-slate-100 p-3"
                      key={order.id}
                    >
                      <div className="flex items-center justify-between text-sm">
                        <p className="font-semibold text-slate-800">{order.id}</p>
                        <p className="text-slate-500">{order.date}</p>
                      </div>
                      <div className="mt-2 flex items-center justify-between text-sm">
                        <p className="text-slate-600">{order.status}</p>
                        <p className="font-bold text-slate-900">{order.total}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h3 className="text-sm font-semibold uppercase tracking-wide text-slate-500">
                  Account Details
                </h3>
                <div className="mt-3 rounded-xl border border-slate-100 p-4 text-sm text-slate-600">
                  <p>Shipping Preference: Standard Delivery</p>
                  <p className="mt-2">Saved Address: 223 Market Street, Seattle</p>
                </div>
              </div>

              <Button onClick={handleLogout} variant="secondary">
                Logout
              </Button>
            </div>
          ) : (
            <div className="mt-5 rounded-xl border border-dashed border-slate-200 p-6 text-sm text-slate-500">
              Login to view your order history, account details, and logout controls.
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

function InputField({ label, onChange, type = "text", value }) {
  return (
    <label className="block">
      <span className="mb-1 block text-sm font-medium text-slate-700">{label}</span>
      <input
        className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-700 focus:border-primary-500 focus:outline-none"
        onChange={onChange}
        required
        type={type}
        value={value}
      />
    </label>
  );
}

export default LoginPage;
